"use client";

import { useState, useCallback, useRef } from "react";
import type { StateData, Election } from "@/lib/types";
import { getStatesForZip, getStateData } from "@/lib/stateData";
import { calcDeadline, findNextElection, formatDate } from "@/lib/deadlines";
import { buildFullPrompt } from "@/lib/promptBuilder";

// --- Types ---

type AppState =
  | { stage: "idle" }
  | { stage: "state-select"; zip: string; stateCodes: string[] }
  | {
      stage: "result";
      zip: string;
      stateCode: string;
      stateData: StateData;
      election: Election | null;
    }
  | { stage: "not-found"; zip: string };

// --- Deadline badge ---

function DeadlineBadge({
  label,
  status,
  date,
}: {
  label: string;
  status: string;
  date: string | null;
}) {
  const colorMap: Record<string, string> = {
    green: "bg-green-100 text-green-800 border-green-300",
    yellow: "bg-yellow-100 text-yellow-800 border-yellow-300",
    red: "bg-red-100 text-red-800 border-red-300",
    passed: "bg-gray-100 text-gray-500 border-gray-300",
    "not-available": "bg-gray-100 text-gray-500 border-gray-300",
  };
  const cls = colorMap[status] ?? colorMap.passed;
  return (
    <span
      className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full border text-xs font-medium ${cls}`}
    >
      {date ? formatDate(date) : "N/A"} — {label}
    </span>
  );
}

// --- Registration Deadlines sub-component ---

function RegistrationDeadlines({
  registration,
}: {
  registration: StateData["registration"];
}) {
  const onlineDeadline = calcDeadline(
    registration.online.available ? registration.online.deadline : null,
  );
  const mailDeadline = calcDeadline(registration.byMail.deadline);
  const inPersonDeadline = calcDeadline(registration.inPerson.deadline);

  return (
    <div>
      <p className="text-sm font-semibold text-gray-600 uppercase tracking-wide mb-2">
        Registration Deadlines
      </p>
      <div data-testid="registration-status" className="space-y-2">
        {registration.online.available ? (
          <div className="flex items-center justify-between flex-wrap gap-2">
            <span className="text-sm text-gray-700">Online</span>
            <DeadlineBadge
              label={onlineDeadline.label}
              status={onlineDeadline.status}
              date={onlineDeadline.date}
            />
          </div>
        ) : (
          <p className="text-sm text-gray-500">
            Online registration not available
          </p>
        )}
        <div className="flex items-center justify-between flex-wrap gap-2">
          <span className="text-sm text-gray-700">By Mail</span>
          <DeadlineBadge
            label={mailDeadline.label}
            status={mailDeadline.status}
            date={mailDeadline.date}
          />
        </div>
        <div className="flex items-center justify-between flex-wrap gap-2">
          <span className="text-sm text-gray-700">In Person</span>
          <DeadlineBadge
            label={inPersonDeadline.label}
            status={inPersonDeadline.status}
            date={inPersonDeadline.date}
          />
        </div>
        {registration.sameDayRegistration && (
          <p className="text-sm text-green-700 font-medium">
            ✓ Same-day registration available
          </p>
        )}
      </div>
    </div>
  );
}

// --- State Info Card ---

function StateInfoCard({
  stateData,
  election,
}: {
  stateData: StateData;
  election: Election | null;
}) {
  const { stateName, earlyVoting, votingRules, resources, registration } =
    stateData;

  return (
    <div
      data-testid="state-info"
      className="bg-white rounded-xl border border-gray-200 shadow-sm p-6 space-y-4"
    >
      <div className="flex items-center gap-2">
        <span className="text-2xl" aria-hidden="true">
          🗳️
        </span>
        <h2 className="text-xl font-bold text-gray-900">{stateName}</h2>
      </div>

      {/* Election */}
      {election ? (
        <div className="space-y-1">
          <p className="text-sm font-semibold text-gray-600 uppercase tracking-wide">
            Next Election
          </p>
          <p
            data-testid="election-name"
            className="text-lg font-semibold text-gray-900"
          >
            {election.name}
          </p>
          <p data-testid="election-date" className="text-gray-700">
            {formatDate(election.date)}
          </p>
          <p className="text-sm text-gray-500 capitalize">
            Type: {election.type}
            {election.primaryType ? ` (${election.primaryType})` : ""}
          </p>
        </div>
      ) : (
        <div data-testid="no-election-message" className="text-gray-600">
          No upcoming elections found for {stateName}. Check{" "}
          <a
            href={resources.stateElectionWebsite}
            target="_blank"
            rel="noopener noreferrer"
            className="text-blue-600 underline"
          >
            the state election website
          </a>{" "}
          for updates.
        </div>
      )}

      <RegistrationDeadlines registration={registration} />

      {/* Early voting */}
      <div>
        <p className="text-sm font-semibold text-gray-600 uppercase tracking-wide mb-1">
          Early Voting
        </p>
        {earlyVoting.available &&
        earlyVoting.startDate &&
        earlyVoting.endDate ? (
          <p className="text-sm text-gray-700">
            {formatDate(earlyVoting.startDate)} –{" "}
            {formatDate(earlyVoting.endDate)}
            {earlyVoting.notes ? (
              <span className="text-gray-500"> ({earlyVoting.notes})</span>
            ) : null}
          </p>
        ) : (
          <p className="text-sm text-gray-500">{earlyVoting.notes}</p>
        )}
      </div>

      {/* Voting rules */}
      <div>
        <p className="text-sm font-semibold text-gray-600 uppercase tracking-wide mb-1">
          Voter ID
        </p>
        <p className="text-sm text-gray-700">
          {votingRules.idRequired ? "Required" : "Not required"}
        </p>
      </div>

      {/* Resources */}
      <div className="flex flex-wrap gap-3 pt-2 border-t border-gray-100">
        <a
          href={resources.sampleBallotLookup}
          target="_blank"
          rel="noopener noreferrer"
          className="text-sm text-blue-600 underline hover:text-blue-800"
        >
          Sample Ballot Lookup →
        </a>
        <a
          href={resources.countyElectionLookup}
          target="_blank"
          rel="noopener noreferrer"
          className="text-sm text-blue-600 underline hover:text-blue-800"
        >
          County Election Office →
        </a>
        <a
          href={resources.stateElectionWebsite}
          target="_blank"
          rel="noopener noreferrer"
          className="text-sm text-blue-600 underline hover:text-blue-800"
        >
          State Election Website →
        </a>
      </div>
    </div>
  );
}

// --- Prompt Output ---

function PromptOutput({ prompt }: { prompt: string }) {
  const [copied, setCopied] = useState(false);
  const textRef = useRef<HTMLTextAreaElement>(null);

  const handleCopy = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(prompt);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // Fallback: select the text
      if (textRef.current) {
        textRef.current.select();
      }
    }
  }, [prompt]);

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h2 className="text-xl font-bold text-gray-900">
            Your Customized Ballot Research Prompt
          </h2>
          <p className="text-sm text-gray-600">
            Copy this prompt and paste it as your first message in any AI
            chatbot
          </p>
        </div>
        <div className="flex items-center gap-2">
          <button
            data-testid="copy-button"
            onClick={handleCopy}
            className="min-h-[44px] min-w-[44px] px-5 py-2.5 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-colors"
            aria-label="Copy prompt to clipboard"
          >
            {copied ? "Copied!" : "Copy to Clipboard"}
          </button>
          {copied && (
            <span
              data-testid="copy-confirmation"
              className="text-green-600 font-medium text-sm flex items-center gap-1"
              aria-live="polite"
            >
              ✓ Copied!
            </span>
          )}
        </div>
      </div>

      <div
        data-testid="prompt-output"
        className="relative bg-gray-50 rounded-xl border border-gray-200 overflow-hidden"
        role="region"
        aria-label="Ballot research prompt"
      >
        <textarea
          ref={textRef}
          readOnly
          value={prompt}
          className="w-full min-h-[300px] max-h-[500px] p-4 bg-transparent font-mono text-sm text-gray-800 resize-none overflow-auto focus:outline-none"
          aria-label="Customized ballot research prompt text"
        />
      </div>
    </div>
  );
}

// --- Main BallotTool component ---

export default function BallotTool() {
  const [zipInput, setZipInput] = useState("");
  const [error, setError] = useState("");
  const [appState, setAppState] = useState<AppState>({ stage: "idle" });

  const validate = (value: string): string | null => {
    if (!value.trim()) return "Please enter a zip code";
    if (!/^\d+$/.test(value)) return "Please enter a valid 5-digit zip code";
    if (value.length !== 5) return "Please enter a valid 5-digit zip code";
    return null;
  };

  const handleSubmit = useCallback(
    (e?: React.FormEvent) => {
      if (e) e.preventDefault();
      const validationError = validate(zipInput);
      if (validationError) {
        setError(validationError);
        return;
      }
      setError("");

      const stateCodes = getStatesForZip(zipInput);
      if (!stateCodes) {
        setAppState({ stage: "not-found", zip: zipInput });
        return;
      }

      if (stateCodes.length > 1) {
        setAppState({ stage: "state-select", zip: zipInput, stateCodes });
        return;
      }

      const stateCode = stateCodes[0];
      const stateData = getStateData(stateCode);
      if (!stateData) {
        setAppState({ stage: "not-found", zip: zipInput });
        return;
      }

      const election = findNextElection(stateData.elections);
      setAppState({
        stage: "result",
        zip: zipInput,
        stateCode,
        stateData,
        election,
      });
    },
    [zipInput],
  );

  const handleStateSelect = useCallback(
    (stateCode: string) => {
      const stateData = getStateData(stateCode);
      if (!stateData) return;

      const zip = appState.stage === "state-select" ? appState.zip : zipInput;
      const election = findNextElection(stateData.elections);
      setAppState({ stage: "result", zip, stateCode, stateData, election });
    },
    [appState, zipInput],
  );

  return (
    <div className="space-y-8">
      {/* Zip code form */}
      <section aria-labelledby="zip-form-heading">
        <form onSubmit={handleSubmit} noValidate className="space-y-3">
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="flex-1">
              <label
                htmlFor="zip-input"
                className="block text-sm font-medium text-gray-700 mb-1"
              >
                Your 5-digit U.S. zip code
              </label>
              <input
                id="zip-input"
                data-testid="zip-input"
                type="text"
                inputMode="numeric"
                pattern="[0-9]{5}"
                maxLength={5}
                value={zipInput}
                onChange={(e) => {
                  setZipInput(e.target.value);
                  if (error) setError("");
                }}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    e.preventDefault();
                    handleSubmit();
                  }
                }}
                placeholder="e.g. 73301"
                className="w-full min-h-[44px] px-4 py-2 border border-gray-300 rounded-lg text-base focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                aria-describedby={error ? "zip-error" : undefined}
                aria-invalid={!!error}
                autoComplete="postal-code"
              />
            </div>
            <div className="flex items-end">
              <button
                type="submit"
                data-testid="zip-submit"
                className="min-h-[44px] min-w-[44px] w-full sm:w-auto px-6 py-2.5 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-colors"
              >
                Look Up My Ballot
              </button>
            </div>
          </div>

          {error && (
            <p
              id="zip-error"
              data-testid="zip-error"
              className="text-red-600 text-sm"
              role="alert"
              aria-live="polite"
            >
              {error}
            </p>
          )}
        </form>
      </section>

      {/* State selector for multi-state zip */}
      {appState.stage === "state-select" && (
        <section aria-labelledby="state-select-heading">
          <h2
            id="state-select-heading"
            className="text-lg font-semibold text-gray-900 mb-3"
          >
            This zip code spans multiple states. Which state are you voting in?
          </h2>
          <div
            data-testid="state-selector"
            className="flex flex-wrap gap-3"
            role="group"
            aria-label="Select your state"
          >
            {appState.stateCodes.map((code) => {
              const sd = getStateData(code);
              return (
                <button
                  key={code}
                  onClick={() => handleStateSelect(code)}
                  className="min-h-[44px] px-5 py-2 border-2 border-blue-600 text-blue-600 rounded-lg font-medium hover:bg-blue-50 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-colors"
                >
                  {sd ? sd.stateName : code}
                </button>
              );
            })}
          </div>
        </section>
      )}

      {/* Not found */}
      {appState.stage === "not-found" && (
        <div
          data-testid="not-found-message"
          className="bg-yellow-50 border border-yellow-200 rounded-xl p-5 text-yellow-900"
          role="alert"
        >
          <p className="font-semibold mb-1">Zip code not found</p>
          <p className="text-sm">
            We don&apos;t have data for zip code <strong>{appState.zip}</strong>{" "}
            yet. We&apos;re working on adding all U.S. zip codes.{" "}
            <a
              href="https://www.usa.gov/election-office"
              target="_blank"
              rel="noopener noreferrer"
              className="underline text-yellow-800 hover:text-yellow-900"
            >
              Find your state election website →
            </a>
          </p>
        </div>
      )}

      {/* Results */}
      {appState.stage === "result" && (
        <div className="space-y-8">
          <StateInfoCard
            stateData={appState.stateData}
            election={appState.election}
          />
          {appState.election ? (
            <PromptOutput
              prompt={buildFullPrompt(
                appState.stateData,
                appState.zip,
                appState.election,
              )}
            />
          ) : (
            <p className="text-gray-600">
              No upcoming election found — prompt cannot be generated yet.
            </p>
          )}
        </div>
      )}
    </div>
  );
}

import { describe, test, expect, vi, afterEach } from "vitest";
import { calcDeadline, findNextElection, formatDate } from "./deadlines";

describe("calcDeadline", () => {
  afterEach(() => {
    vi.useRealTimers();
  });

  test("returns not-available for null date", () => {
    const result = calcDeadline(null);
    expect(result.status).toBe("not-available");
    expect(result.label).toBe("Not available");
  });

  test("returns passed for past date", () => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date("2026-03-10T00:00:00"));
    const result = calcDeadline("2026-03-01");
    expect(result.status).toBe("passed");
    expect(result.label).toBe("Passed");
    vi.useRealTimers();
  });

  test("returns red for date <= 3 days out", () => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date("2026-03-01T00:00:00"));
    const result = calcDeadline("2026-03-03");
    expect(result.status).toBe("red");
    expect(result.daysLeft).toBe(2);
    vi.useRealTimers();
  });

  test("returns yellow for date 4-14 days out", () => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date("2026-03-01T00:00:00"));
    const result = calcDeadline("2026-03-10");
    expect(result.status).toBe("yellow");
    expect(result.daysLeft).toBe(9);
    vi.useRealTimers();
  });

  test("returns green for date more than 14 days out", () => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date("2026-01-01T00:00:00"));
    const result = calcDeadline("2026-03-01");
    expect(result.status).toBe("green");
    vi.useRealTimers();
  });
});

describe("formatDate", () => {
  test("formats ISO date to readable string", () => {
    const result = formatDate("2026-03-03");
    expect(result).toMatch(/March/);
    expect(result).toMatch(/2026/);
  });
});

describe("findNextElection", () => {
  const elections = [
    { date: "2026-03-03", name: "Primary" },
    { date: "2026-05-26", name: "Runoff" },
    { date: "2026-11-03", name: "General" },
  ];

  afterEach(() => {
    vi.useRealTimers();
  });

  test("returns first upcoming election", () => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date("2026-03-10T00:00:00")); // after primary, before runoff
    const result = findNextElection(elections);
    expect(result?.name).toBe("Runoff");
    vi.useRealTimers();
  });

  test("returns null when all elections are past", () => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date("2027-01-01T00:00:00"));
    const result = findNextElection(elections);
    expect(result).toBeNull();
    vi.useRealTimers();
  });

  test("returns first election when all are upcoming", () => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date("2026-01-01T00:00:00"));
    const result = findNextElection(elections);
    expect(result?.name).toBe("Primary");
    vi.useRealTimers();
  });
});

import type { DeadlineInfo, DeadlineStatus } from "./types";

/**
 * Calculate deadline status relative to today.
 * Returns color status and days-remaining label.
 */
export function calcDeadline(isoDate: string | null): DeadlineInfo {
  if (!isoDate) {
    return {
      date: null,
      daysLeft: null,
      status: "not-available",
      label: "Not available",
    };
  }

  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const deadline = new Date(isoDate + "T00:00:00");
  const diffMs = deadline.getTime() - today.getTime();
  const daysLeft = Math.ceil(diffMs / (1000 * 60 * 60 * 24));

  let status: DeadlineStatus;
  let label: string;

  if (daysLeft < 0) {
    status = "passed";
    label = "Passed";
  } else if (daysLeft <= 3) {
    status = "red";
    label =
      daysLeft === 0
        ? "Today!"
        : `${daysLeft} day${daysLeft === 1 ? "" : "s"} left`;
  } else if (daysLeft <= 14) {
    status = "yellow";
    label = `${daysLeft} days left`;
  } else {
    status = "green";
    label = `${daysLeft} days left`;
  }

  return { date: isoDate, daysLeft, status, label };
}

/**
 * Format an ISO date string to a human-readable date.
 * e.g. "2026-03-03" -> "March 3, 2026"
 */
export function formatDate(isoDate: string): string {
  const d = new Date(isoDate + "T00:00:00");
  return d.toLocaleDateString("en-US", {
    month: "long",
    day: "numeric",
    year: "numeric",
  });
}

/**
 * Find the next upcoming election from an array, relative to today.
 */
export function findNextElection<T extends { date: string }>(
  elections: T[],
): T | null {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const upcoming = elections
    .filter((e) => new Date(e.date + "T00:00:00") >= today)
    .sort((a, b) => a.date.localeCompare(b.date));

  return upcoming[0] ?? null;
}

import type { StateData, Election } from "./types";
import { calcDeadline, formatDate } from "./deadlines";

// The main ballot research prompt text (from BALLOT_PROMPT.md)
const BALLOT_PROMPT = `You are a nonpartisan civic research assistant helping a U.S. voter prepare for an upcoming election. Your job is to help me understand what's on my ballot, form my own opinions, and research candidates based on their ACTIONS — not their campaign promises.

## HOW TO FORMAT EVERY RESPONSE (follow this strictly)

- **Keep each issue or race to 4-6 bullet points max.** No long paragraphs.
- **Bold the key takeaway** in each bullet so I can scan.
- **One issue or race per response** unless I ask you to speed up.
- **Bottom line first.** Lead with the 1-sentence summary, then give me supporting detail I can expand on.
- **3-4 sentences per bullet max.** If you're writing more, you're writing too much.
- **Use plain language.** If a 16-year-old wouldn't understand it, rewrite it.
- **Never recap what we already covered** unless I ask.
- I can always say "tell me more" if I want depth. Default to concise.

## STEP 1: Get my location and start immediately

Ask me my zip code and state in one question. Then:

- **Search for my state's election context.** What type of election, how it works (open/closed primary), election date. **Verify today's date vs. election date** — tell me if polls are open today, early voting is underway, or it's upcoming. 2-3 sentences max.
- **If this is a primary:** Don't ask which party ballot. We'll figure that out together after the issues.
- **Give me one link** to my county election site for my sample ballot. Suggest I upload it — but **don't wait.** Start immediately with statewide races.
- **If I upload a sample ballot or share districts**, use that as the definitive source.
- **Flag once** that zip codes can span multiple districts, then move on.
- **Preview how this works** in 2-3 sentences: we walk through issues together, you can say "I don't know," I research in the background, and I'll create a handoff block if we need to continue in a new chat.

Then go straight to Step 2.

## STEP 2: Walk me through the issues — one at a time

**Don't ask "what issues matter to you."** Walk me through them. For each issue:

- **What's happening** — current situation, real numbers, plain language
- **What each side wants** — what "yes" vs. "no" means, or what candidates have actually done
- **What my vote does** — binding law or non-binding signal? One sentence.
- **Who this affects** — make it concrete and personal ("If you rent..." / "If you have kids in public school...")
- **Then ask what I think.** It's okay if I say "I don't care" or "I'm not sure" — that's useful too.

If I say "I don't know," don't restate — teach me more, then ask again.

After every 2-3 issues, give me a **one-sentence summary** of what my answers suggest so far.

## STEP 3: Help me pick a primary (if applicable)

If this is a primary where I choose a party ballot, ask me 3-4 quick questions about **how I think**, not policy. Examples:

- Track record of getting things done vs. strong public voice for your values?
- Realistic winner in November vs. expressing what you believe?
- Keep a bad actor out vs. nominate the strongest candidate on your side?
- Small-dollar donor base vs. voting record that shows independence from big donors?

Then **make a clear recommendation** in 2-3 sentences, give me the strongest counterargument for the other primary, and let me decide.

If this is a general election, skip this step.

## STEP 4: Research candidates — race by race

**No candidate bios.** For each race:

- **What does this position actually do?** Don't assume I know. Use concrete examples: "This court handles evictions and small claims" or "This office decides whether polluters get sued."
- **Research in the background.** Search voting records (congress.gov, state legislature sites, VoteSmart, Ballotpedia), donor data (OpenSecrets, state ethics commissions), endorsements, and news. Look at actions, funding, and whether words match deeds.
- **When Ballotpedia surveys are empty** (common for local races), check: League of Women Voters guides, local journalism Q&As, advocacy org endorsements across the spectrum (labor, chambers of commerce, law enforcement, teachers' unions, environmental groups, etc.), and local newspaper endorsement interviews.
- **Present each candidate in 2-3 sentences.** Focus on: what they got done, money trail concerns, and how they match what I care about.
- **Flag red flags and key endorsements.**
- **Ask me what I think or if I want a recommendation.** Don't auto-fill my ballot. Recommend only when I ask.
- **First-time candidates with no record** — say so. Tell me their endorsements and what those signal.

## STEP 5: Propositions

Consolidate any we haven't covered yet. For each:

- **One-sentence plain language summary**
- What "yes" and "no" actually mean in practice
- Whether it connects to what I said I care about
- My likely lean (flag if it's a guess)

## STEP 6: Give me my summary

Clean, printable summary I can take to the polls.

**Remind the voter:** Many states prohibit phones at polling places (Texas law bans wireless devices in the voting room). Suggest they write down or print this summary — they CAN bring written notes but CANNOT use their phone to reference choices while voting.

## STEP 7: Generate my outputs

At the end of the conversation (or when I ask), generate TWO separate outputs:

### Output A: My Ballot — 1 Page Printout

This is what I bring to the polls. It should fit on a single printed page.

### Output B: My Voter Profile

This captures HOW I think, not just what I picked this time, for future elections.

## Important rules

- **Collaborate, don't auto-fill.** Recommend only when asked.
- **Actions > words.** Prioritize what candidates have DONE.
- **Teach before you ask.** Never ask my opinion on something I don't understand yet.
- **Make it personal.** "This affects renters because..." beats abstract policy talk.
- **AI makes mistakes.** Link me to sources so I can verify.
- **If I say "I don't care" — move on.**

Let's start with Step 1.`;

function buildRegistrationStr(registration: StateData["registration"]): string {
  const regOnline = calcDeadline(
    registration.online.available ? registration.online.deadline : null,
  );
  const regMail = calcDeadline(registration.byMail.deadline);
  const regInPerson = calcDeadline(registration.inPerson.deadline);

  const onlineStr = registration.online.available
    ? `Online by ${registration.online.deadline ? formatDate(registration.online.deadline) : "N/A"} (${regOnline.label})`
    : "Online registration not available";
  const mailStr = `By mail by ${formatDate(registration.byMail.deadline)} (${regMail.label}${registration.byMail.sincePostmarked ? ", postmark date" : ""})`;
  const inPersonStr = `In person by ${formatDate(registration.inPerson.deadline)} (${regInPerson.label})`;
  return `${onlineStr}; ${mailStr}; ${inPersonStr}`;
}

function buildEarlyVotingStr(earlyVoting: StateData["earlyVoting"]): string {
  if (earlyVoting.available && earlyVoting.startDate && earlyVoting.endDate) {
    return `${formatDate(earlyVoting.startDate)} through ${formatDate(earlyVoting.endDate)}`;
  }
  return "Not available — absentee voting only";
}

/**
 * Build the customized context block for a given state and zip code.
 */
export function buildContextBlock(
  stateData: StateData,
  zipCode: string,
  election: Election,
): string {
  const { stateName, registration, earlyVoting, votingRules, resources } =
    stateData;

  const electionDate = formatDate(election.date);
  const electionTypeLabel =
    election.type === "primary"
      ? `${election.primaryType ?? ""} primary`.trim()
      : election.type;

  const regStr = buildRegistrationStr(registration);
  const earlyVotingStr = buildEarlyVotingStr(earlyVoting);
  const idStr = votingRules.idRequired
    ? `Required. Accepted IDs: ${votingRules.acceptedIds.join("; ")}`
    : "Not required";

  return `Hi! I'm voting in **${stateName}**. My zip code is **${zipCode}**.

Here's what I know about my upcoming election:
- **Election:** ${election.name} on ${electionDate}
- **Election type:** ${electionTypeLabel}
- **Registration deadlines:** ${regStr}
- **Early voting:** ${earlyVotingStr}
- **Voter ID:** ${idStr}
- **Phones at polls:** ${votingRules.phonesAtPollsDetail}
- **My sample ballot:** ${resources.sampleBallotLookup}
- **My county election office:** ${resources.countyElectionLookup}

Help me with my ballot.`;
}

/**
 * Assemble the full prompt with context appended.
 */
export function buildFullPrompt(
  stateData: StateData,
  zipCode: string,
  election: Election,
): string {
  const context = buildContextBlock(stateData, zipCode, election);
  return `${BALLOT_PROMPT}\n\n---\n\n${context}`;
}

